// ── DEBUG PANEL (diagnostic Samsung) ─────────────────────────────────────────
// Capture toutes les erreurs JS et les affiche sur l'écran via bouton secret
const debugLogs = [];
const _origError = console.error.bind(console);
console.error = (...args) => { debugLogs.push("ERR: " + args.join(" ")); _origError(...args); };
window.addEventListener("error", e => debugLogs.push("JS: " + e.message + " @ " + e.filename + ":" + e.lineno));
window.addEventListener("unhandledrejection", e => debugLogs.push("PROMISE: " + (e.reason?.message || e.reason)));

function DebugPanel() {
  const [open, setOpen] = useState(false);
  const [logs, setLogs] = useState([]);
  const refresh = () => setLogs([...debugLogs]);
  return (
    <>
      {/* Bouton secret : coin bas-gauche, transparent */}
      <div onClick={()=>{refresh();setOpen(o=>!o);}}
        style={{position:"fixed",bottom:8,left:8,width:32,height:32,zIndex:99999,opacity:0.01,cursor:"pointer"}}/>
      {open && (
        <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.92)",zIndex:99998,overflowY:"auto",padding:16,fontFamily:"monospace",fontSize:11,color:"#0f0"}}>
          <div style={{display:"flex",justifyContent:"space-between",marginBottom:12}}>
            <span style={{color:"#ff0",fontWeight:700,fontSize:14}}>🐛 DEBUG PANEL</span>
            <button onClick={()=>setOpen(false)} style={{background:"#c00",color:"#fff",border:"none",borderRadius:4,padding:"4px 10px",fontSize:12}}>✕ Fermer</button>
          </div>
          <div style={{marginBottom:8,color:"#aaa"}}>UA: {navigator.userAgent.substring(0,80)}</div>
          <div style={{marginBottom:8,color:"#aaa"}}>URL: {window.location.href}</div>
          <div style={{marginBottom:8,color:"#aaa"}}>Online: {navigator.onLine?"oui":"non"}</div>
          <hr style={{borderColor:"#333",margin:"8px 0"}}/>
          {logs.length === 0
            ? <div style={{color:"#888"}}>Aucune erreur capturée ✓</div>
            : logs.map((l,i)=><div key={i} style={{marginBottom:6,color:"#f88",wordBreak:"break-all"}}>{l}</div>)
          }
          <hr style={{borderColor:"#333",margin:"8px 0"}}/>
          <button onClick={()=>{debugLogs.length=0;refresh();}} style={{background:"#333",color:"#fff",border:"none",borderRadius:4,padding:"4px 10px",fontSize:11,marginTop:4}}>Effacer les logs</button>
        </div>
      )}
    </>
  );
}

